import React, { useRef, useState } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import LottieView from 'lottie-react-native';
import Animated, { FadeIn } from 'react-native-reanimated';

const OrderConfirmationScreen = () => {
  const animationRef = useRef<LottieView>(null);
  const [showText, setShowText] = useState(false);

  return (
    <View style={styles.container}>
      <LottieView
        ref={animationRef}
        source={require('../assets/success-check.json')} // Assurez-vous d'avoir ce fichier
        autoPlay
        loop={false}
        onAnimationFinish={() => setShowText(true)}
        style={styles.animation}
      />
      {showText && (
        <Animated.View entering={FadeIn.duration(500)}>
          <Text style={styles.text}>Commande confirmée ✅</Text>
          <Text style={styles.subText}>Merci pour votre achat !</Text>
        </Animated.View>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#fff',
  },
  animation: {
    width: 200,
    height: 200,
  },
  text: {
    fontSize: 24,
    fontWeight: 'bold',
    marginTop: 20,
    color: '#2e7d32',
  },
  subText: {
    fontSize: 16,
    marginTop: 10,
    color: '#555',
  },
});

export default OrderConfirmationScreen;
